const item = $input.first().json.content[0] || null;

const dataAtual = Date.now();
const trintaDiasEmMs = 30 * 24 * 60 * 60 * 1000; // 30 dias = 2592000000
const limiteMs = dataAtual + trintaDiasEmMs;

const vigenciaAteAjustada = item.vigenciaAteAjustada || item.vigenciaAte || 0;

return {
  alreadyRenew: vigenciaAteAjustada > limiteMs
}

const message = $("getClientFromAPI").first().json.error.message.replace('400 - ', '');
const obj = JSON.parse(JSON.parse(message));
const r = obj?.message || 'Erro da API';
return { error: r };

const answers = $input.first().json.content.anamneseRespostas;

const response = [];
for (const i in answers) {
  const idx = parseInt(i);
  if (idx < 6) continue;
  const a = answers[idx];
  const answer = a.anamnesePergunta;
  let value = a.resposta;
  if (Array.isArray(answer['opcoes'])) {
    value = answer['opcoes'].reduce((acc, item) => {
      if (Array.isArray(value)) {
        if (value.includes(item.id)) {
          acc.push(item.nome);
        }
      } else if (value == item.id){
        acc.push(item.nome);
      }
      return acc;
    }, []).join(', ');
  }

  const obs = a?.observacao;

  if (!value && !obs) continue;

  let r = `pergunta: ${a.anamnesePergunta.pergunta}\n`;

  if (value)
    r += `resposta: ${value}\n`;

  if (obs)
     r += `observacao: ${obs}\n`;

  response.push(r);
}

return { anamnese: response.join("\n") };

