const contracts = $input.first().json.content || [];
const dataAtual = Date.now();
const trintaDiasEmMs = 30 * 24 * 60 * 60 * 1000;
const limiteMs = dataAtual + trintaDiasEmMs;

const futureContract = contracts.find(c => (c.vigenciaDe || 0) > dataAtual);
const currentContract = contracts.find(c => (c.vigenciaDe || 0) <= dataAtual) || contracts[0] || null;

const referenceContract = futureContract || currentContract;
const vigenciaAteAjustada = referenceContract?.vigenciaAteAjustada || referenceContract?.vigenciaAte || 0;

// Plano de 30 dias = 1 mês
const is30DayPlan = (currentContract?.contratoDuracao?.numeroMeses || 0) === 1;

return {
  alreadyRenew: vigenciaAteAjustada > limiteMs,
  is30DayPlan,
  hasFutureContract: !!futureContract,
  vigenciaAteAjustada,
  currentContractExpiry: currentContract?.vigenciaAteAjustada || currentContract?.vigenciaAte || 0,
  futureContractExpiry: futureContract?.vigenciaAteAjustada || futureContract?.vigenciaAte || null,
  planoDuracao: currentContract?.contratoDuracao?.numeroMeses || null,
  planoDescricao: currentContract?.descricaoPlano || null
};

const message = $("getClientFromAPI").first().json.error.message.replace('400 - ', '');
const obj = JSON.parse(JSON.parse(message));
const r = obj?.message || 'Erro da API';
return { error: r };

function generate_hash() {
    const chars = 'abcdefghijklmnopqrstuvxywz0123456789';
    const len = chars.length;
    const size = 6;
    let hash = [];

    for (let i = 0; i < size; i++) {
        const char = chars[Math.floor(Math.random() * len)];

        // conta quantas vezes o char já apareceu no hash
        const count = hash.filter(c => c === char).length;

        if (count < 2) {
            hash.push(char);
        }
    }

    return hash.join('');
}

const h = generate_hash();
return [{ hash: h }];

// Campos do retorno
const vinculos = $('getVinculos').first().json.content.vinculos;

const teacher = vinculos.find(v => v.tipoVinculo === "TW")?.colaborador || 'NULL';
const coordinator = vinculos.find(v => v.tipoVinculo === "OR")?.colaborador || 'NULL';
const consultant = vinculos.find(v => v.tipoVinculo === "CO")?.colaborador || 'NULL';

const dt_plan_start = $('getContrato').first().json.content[0].vigenciaDe;
const dt_plan_finish = $('getContrato').first().json.content[0].vigenciaAteAjustada;

const data = {
  client_id: $('1.loop').first().json.matricula,
  status_pessoa: $('getCodes & getSituacao').first().json.content.situacao,
  status_contrato: $('getCodes & getSituacao').first().json.content.situacaoContrato, 
  teacher: teacher,
  coordinator: coordinator,
  consultant: consultant,
  dt_plan_start: dt_plan_start,
  dt_plan_finish: dt_plan_finish
};

return [ data ];

